import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { API } from "@/App";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";

const loadRazorpay = () => {
  return new Promise((resolve) => {
    const script = document.createElement("script");
    script.src = "https://checkout.razorpay.com/v1/checkout.js";
    script.onload = () => resolve(true);
    script.onerror = () => resolve(false);
    document.body.appendChild(script);
  });
};

const CartPage = ({ user }) => {
  const navigate = useNavigate();
  const [cart, setCart] = useState(null);
  const token = localStorage.getItem("token");

  useEffect(() => {
    fetchCart();
  }, []);

  const fetchCart = async () => {
    try {
      const res = await axios.get(`${API}/cart`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setCart(res.data);
    } catch {
      toast.error("Failed to load cart");
    }
  };

  const updateQty = async (menu_item_id, quantity) => {
    try {
      await axios.put(
        `${API}/cart/update`,
        { menu_item_id, quantity },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      fetchCart();
    } catch {
      toast.error("Failed to update cart");
    }
  };

  const handlePlaceOrder = async () => {
    const ok = await loadRazorpay();
    if (!ok) {
      toast.error("Razorpay failed to load");
      return;
    }

    try {
      const res = await axios.post(
        `${API}/orders/create-payment`,
        { delivery_address: user.address || "Not provided" },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      const { key, amount, currency, razorpay_order_id } = res.data;

      const options = {
        key,
        amount,
        currency,
        name: "FoodHUB",
        description: "Food Order Payment",
        order_id: razorpay_order_id,
        handler: async function (response) {
          await axios.post(
            `${API}/orders/payment-success`,
            {
              razorpay_order_id: response.razorpay_order_id,
              razorpay_payment_id: response.razorpay_payment_id,
              razorpay_signature: response.razorpay_signature,
              delivery_address: user.address,
            },
            { headers: { Authorization: `Bearer ${token}` } }
          );

          toast.success("Order placed successfully");
          navigate("/orders");
        },
        prefill: {
          name: user.name,
          email: user.email,
          contact: user.phone || "",
        },
        theme: { color: "#FF6B6B" },
      };

      new window.Razorpay(options).open();
    } catch {
      toast.error("Payment initiation failed");
    }
  };

  if (!cart || !cart.items?.length) {
    return <p className="p-8 text-center">Cart is empty</p>;
  }

  const total = cart.items.reduce(
    (sum, i) => sum + i.price * i.quantity,
    0
  );

  return (
    <div className="max-w-3xl mx-auto p-6">
      <h1 className="text-2xl font-bold mb-4">Your Cart</h1>

      {cart.items.map((item) => (
        <div key={item.menu_item_id} className="flex justify-between mb-3">
          <div>
            <p className="font-semibold">{item.name}</p>
            <p>₹{item.price}</p>
          </div>
          <div className="flex items-center gap-2">
            <Button onClick={() => updateQty(item.menu_item_id, item.quantity - 1)}>-</Button>
            <span>{item.quantity}</span>
            <Button onClick={() => updateQty(item.menu_item_id, item.quantity + 1)}>+</Button>
          </div>
        </div>
      ))}

      <div className="mt-6 font-bold text-xl">Total: ₹{total + 15}</div>

      <Button className="mt-6 w-full bg-[#FF6B6B]" onClick={handlePlaceOrder}>
        Place Order
      </Button>
    </div>
  );
};

export default CartPage;
